use reqwest::Client; use serde_json::Value; #[tokio::main] async fn main() { let api_key = std::env::var("GEMINI_API_KEYS").unwrap(); let client = Client::new(); let prompt = "AI planner for desktop/Photoshop automation. JSON only, camelCase, no markdown.\nOutput: {\"goal\":\"...\",\"steps\":[{\"id\":\"step_1\",\"action\":\"...\",\"params\":{...},\"expectedResult\":\"...\",\"retryable\":false,\"explanation\":\"...\",\"requiresConfirm\":true}],\"note\":\"...\"}\nRules: Use only supported actions. No invented actions. No raw coords unless param requires it. Empty steps if unsupported.\nFor open_app, just provide the common app name like 'notepad' or 'chrome', not the full path.\nActions: desktop.open_app: Launch a desktop app by file path; desktop.click: Click at screen coordinates with optional button and click count; desktop.move_mouse: Move the mouse cursor to screen coordinates; desktop.type_text: Type the provided text into the focused field; desktop.hotkey: Press a hotkey combination like CTRL+S or ALT+F4; desktop.scroll: Scroll the mouse wheel by a signed amount; desktop.wait: Pause execution for a number of milliseconds; desktop.ui_click: Click a UI element by name/control type; desktop.ui_type: Type text into a UI element by name/control type; desktop.ui_read: Read text/value from a UI element by name/control type\nParams: crop{aspect?,bounds?{x,y,w,h}} levels{inputBlack?,inputWhite?,gamma?} resize.canvas{width,height,unit:px|percent} export.png/jpeg{path?,quality?} rotate/straighten{angle} open_app{path,args?} click{x,y,button?,clickCount?} move_mouse{x,y} type_text{text} hotkey{keys[]} scroll{amount} wait{ms} ui_click{name,controlType?,windowName?} ui_type{name,text,controlType?,windowName?} ui_read{name,controlType?,windowName?}\nControlTypes: Button,Edit,Text,ComboBox,ListItem,MenuItem,CheckBox\nRequest: open brave browser and open youtube"; let payload = serde_json::json!({ "contents": [{ "role": "user", "parts": [{ "text": prompt }] }], "generationConfig": { "temperature": 0.1, "maxOutputTokens": 1024 } }); let res = client.post(&format!("https://generativelanguage.googleapis.com/v1/models/gemini-2.5-flash-lite:generateContent?key={}", api_key)).json(&payload).send().await.unwrap().json::<Value>().await.unwrap(); println!("{}", res["candidates"][0]["content"]["parts"][0]["text"].as_str().unwrap()); }
